const body = $input.item.json.body || $input.item.json;

// Datum: ISO-String → "TTMMJJJJ" für SharePoint
function formatDatum(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  const dd = String(d.getDate()).padStart(2,'0');
  const mm = String(d.getMonth()+1).padStart(2,'0');
  const yyyy = d.getFullYear();
  return dd+mm+yyyy;
}

// Pflichtfeld prüfen
const thema = (body.Thema || body.thema || '').trim();
if (!thema) throw new Error('Pflichtfeld Thema fehlt');

const postTyp   = (body.Post_Typ   || body.postTyp   || 'Standard').trim();
const brief     = (body.Content_Brief || body.textIdee || '').trim();
const datum     = formatDatum(body.Veroeffentlichungsdatum || body.wunschDatum || '');
const uhrzeit   = (body.Uhrzeit   || body.uhrzeit   || '').trim();
const hashtag   = (body.Hashtag_Thema || body.hashtag || '').trim();
const bild      = (body.Bild_Dateiname || body.bildBeschreibung || '').trim();
const freigabe  = (body.Freigabe_Person || 'Judith').trim();
const kommentar = (body.Kommentare || body.notiz || '').trim();

return {
  json: {
    Title:    thema,
    field_1:  thema,
    field_2:  postTyp,
    field_3:  brief,
    field_4:  datum,
    field_5:  uhrzeit,
    field_6:  'Entwurf',
    field_7:  hashtag,
    field_8:  bild,
    field_9:  '',
    field_10: '',
    field_11: freigabe,
    field_12: '',
    field_13: kommentar,
    _eingereichtVon: body._eingereichtVon || 'Judith',
    _eingereichtAm:  body._eingereichtAm  || new Date().toISOString(),
    _postTyp: postTyp,
    _datum:   datum
  }
};

